(async()=>{try{
  // Navegar: Muelle -> Libre -> Embarcar directo -> Adicionales
  function clickOrigin(id){var c=document.querySelector('[data-origin="'+id+'"]');if(c)c.click();}
  function clickAdv(to){var el=document.querySelector('[data-adv="'+to+'"]');if(el){el.click();return true;}return false;}
  clickOrigin('muelle');
  await new Promise(function(r){setTimeout(r,400);});
  clickAdv('libre');
  await new Promise(function(r){setTimeout(r,400);});
  clickAdv('embarcado');
  await new Promise(function(r){setTimeout(r,400);});
  var adicChip=!!document.querySelector('[data-adv="adicionales"]');
  clickAdv('adicionales');
  await new Promise(function(r){setTimeout(r,500);});
  // Activar modo admin para ver la RPC
  var tgl=document.getElementById('adminTgl'); if(tgl) tgl.click();
  await new Promise(function(r){setTimeout(r,300);});
  var out={};
  var pbody=document.getElementById('pbody');
  out.embarcado_tuvoAdicionales=adicChip;
  out.panelTitulo=(document.querySelector('.ptitle')||{}).textContent||'';
  out.notaTieneCerrada=/CERRADA/.test(pbody.textContent);
  out.notaTieneCatalogo=/Muelle|Local|Adulto|Full/.test(pbody.textContent);
  out.notaTieneSuma=/monto \+ adicionales|SUMAN|total a cobrar/.test(pbody.textContent);
  out.rpcVisible=/actualizar_adicionales/.test(pbody.textContent);
  out.siguienteCobrar=!!document.querySelector('[data-adv="cobrar"]');
  out.overflowX=document.documentElement.scrollWidth>window.innerWidth;
  return out;
}catch(e){return{crash:e.message,stack:(e.stack||'').slice(0,300)}}})()
